// C0684 · CRUD JSON
var builder = WebApplication.CreateBuilder(args);
var app = builder.Build();
var items = new List<dynamic>();
var seq = 1;

app.MapGet("/items", () => items);
app.MapPost("/items", (dynamic body) => {
  var it = new { id = seq++, name = (string)(body?.name ?? "") };
  items.Add(it);
  return Results.Json(it, statusCode: 201);
});

app.Run();

